+#include "cJSON.h"
+#include "lodepng.h"
+
+#include <algorithm>
+#include <cmath>
+#include <cstdio>
+#include <cstdlib>
+#include <cstring>
+#include <fstream>
+#include <iostream>
+#include <stdexcept>
+#include <string>
+#include <vector>
+
+static std::string read_file(const char* path) {
+    std::ifstream in(path, std::ios::binary);
+    if (!in) {
+        throw std::runtime_error("failed to open file");
+    }
+    return std::string(std::istreambuf_iterator<char>(in), std::istreambuf_iterator<char>());
+}
+
+static std::vector<float> read_tensor(cJSON* root, const char* name, size_t expected) {
+    cJSON* tensors = cJSON_GetObjectItemCaseSensitive(root, "tensors");
+    cJSON* tensor = cJSON_GetObjectItemCaseSensitive(tensors, name);
+    cJSON* data = cJSON_GetObjectItemCaseSensitive(tensor, "data");
+    if (!cJSON_IsArray(data) || cJSON_GetArraySize(data) != static_cast<int>(expected)) {
+        throw std::runtime_error("invalid tensor data");
+    }
+
+    std::vector<float> values(expected);
+    for (size_t i = 0; i < expected; ++i) {
+        cJSON* item = cJSON_GetArrayItem(data, static_cast<int>(i));
+        if (!cJSON_IsNumber(item)) {
+            throw std::runtime_error("invalid tensor value");
+        }
+        values[i] = static_cast<float>(item->valuedouble);
+    }
+    return values;
+}
+
+static void linear_relu(const std::vector<float>& input,
+                        const std::vector<float>& weight,
+                        const std::vector<float>& bias,
+                        std::vector<float>& output,
+                        size_t in_dim,
+                        size_t out_dim,
+                        bool relu) {
+    output.assign(out_dim, 0.0f);
+    for (size_t o = 0; o < out_dim; ++o) {
+        float sum = bias[o];
+        const size_t row = o * in_dim;
+        for (size_t i = 0; i < in_dim; ++i) {
+            sum += weight[row + i] * input[i];
+        }
+        output[o] = relu && sum < 0.0f ? 0.0f : sum;
+    }
+}
+
+static std::vector<float> load_image(const char* path) {
+    std::vector<unsigned char> rgba;
+    unsigned width = 0;
+    unsigned height = 0;
+    unsigned err = lodepng::decode(rgba, width, height, path);
+    if (err) {
+        throw std::runtime_error("failed to decode png");
+    }
+
+    std::vector<float> pixels(28 * 28);
+    for (unsigned y = 0; y < 28; ++y) {
+        for (unsigned x = 0; x < 28; ++x) {
+            unsigned sx = std::min(width - 1, (x * width) / 28);
+            unsigned sy = std::min(height - 1, (y * height) / 28);
+            size_t idx = 4 * (sy * width + sx);
+            float r = rgba[idx + 0] / 255.0f;
+            float g = rgba[idx + 1] / 255.0f;
+            float b = rgba[idx + 2] / 255.0f;
+            float a = rgba[idx + 3] / 255.0f;
+            float gray = (0.299f * r + 0.587f * g + 0.114f * b) * a;
+            pixels[y * 28 + x] = gray;
+        }
+    }
+    return pixels;
+}
+
+int main(int argc, char** argv) {
+    if (argc != 3) {
+        return 1;
+    }
+
+    try {
+        std::string json = read_file(argv[1]);
+        cJSON* root = cJSON_ParseWithLength(json.c_str(), json.size());
+        if (!root) {
+            throw std::runtime_error("failed to parse weights");
+        }
+
+        std::vector<float> w1 = read_tensor(root, "input_layer.weight", 16 * 784);
+        std::vector<float> b1 = read_tensor(root, "input_layer.bias", 16);
+        std::vector<float> w2 = read_tensor(root, "hidden_layer.weight", 16 * 16);
+        std::vector<float> b2 = read_tensor(root, "hidden_layer.bias", 16);
+        std::vector<float> w3 = read_tensor(root, "output_layer.weight", 10 * 16);
+        std::vector<float> b3 = read_tensor(root, "output_layer.bias", 10);
+        cJSON_Delete(root);
+
+        std::vector<float> x = load_image(argv[2]);
+        std::vector<float> h1;
+        std::vector<float> h2;
+        std::vector<float> logits;
+        linear_relu(x, w1, b1, h1, 784, 16, true);
+        linear_relu(h1, w2, b2, h2, 16, 16, true);
+        linear_relu(h2, w3, b3, logits, 16, 10, false);
+
+        int best = 0;
+        for (int i = 1; i < 10; ++i) {
+            if (logits[i] > logits[best]) {
+                best = i;
+            }
+        }
+        std::cout << best << '\n';
+        return 0;
+    } catch (...) {
+        return 1;
+    }
+}
